# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.sugar.verified","kind":"function","src_hash":"70fb2accdcde1211","in":{"base":"str"},"out":{"base":"Any"},"spec":{"lhs":"verified(gua)","rhs":"decorator: generate and (optionally) auto-prove obligations","over":{"base":"str"},"name":"verified_correct"},"guarantee":"decorator: generate and (optionally) auto-prove obligations","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.sugar.verified_correct","statement":"Path(verified(x), decorator: generate and (optionally) auto-prove obligations)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"dee6bfdccd3ebd9e"}
def verified(guarantee: str,
             libraries: Optional[List[str]] = None,
             auto_prove: bool = True):
    """Decorator: generate and (optionally) auto-prove obligations.

    Usage::

        @verified("returns sorted list that is a permutation of input")
        def my_sort(xs: list[int]) -> list[int]:
            return sorted(xs)

    This:
    1. Generates proof obligations from the function body
    2. If auto_prove=True, attempts to resolve them automatically
    3. Attaches the obligation bundle and any proofs as attributes

    The decorated function works normally at runtime — verification
    is a compile-time/analysis-time concern.
    """
    def decorator(func: Callable) -> Callable:
        source = textwrap.dedent(inspect.getsource(func))
        bundle = obligate(source, guarantee, libraries)

        if auto_prove:
            _auto_resolve(bundle)

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            return func(*args, **kwargs)

        wrapper.__obligations__ = bundle  # type: ignore
        wrapper.__guarantee__ = guarantee  # type: ignore
        wrapper.__verified__ = bundle.all_resolved  # type: ignore
        return wrapper
    return decorator


