# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.sugar.list_library_axioms","kind":"function","src_hash":"dd6af7644c4eba7a","in":{"base":"Optional[str]"},"out":{"base":"str"},"spec":{"lhs":"list_library_axioms(lib)","rhs":"list available library axioms for use in proofs","over":{"base":"Optional[str]"},"name":"list_library_axioms_correct"},"guarantee":"list available library axioms for use in proofs","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.sugar.list_library_axioms_correct","statement":"Path(list_library_axioms(x), list available library axioms for use in proofs)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c008279ab694db57"}
def list_library_axioms(library: Optional[str] = None) -> str:
    """List available library axioms for use in proofs.

    Usage::
        print(list_library_axioms("sympy"))
        print(list_library_axioms())  # all libraries
    """
    lines = []
    libs = {library: get_library(library)} if library else all_libraries()

    for lib_name, theory in sorted(libs.items()):
        if theory is None:
            lines.append(f'⚠ Library {lib_name} not registered')
            continue

        lines.append(f'═══ {theory.summary} ═══')

        contracts = theory.all_contracts()
        if contracts:
            lines.append('  Functions:')
            for name, c in sorted(contracts.items()):
                lines.append(f'    {c.qualname}({", ".join(p[0] for p in c.parameters)})')
                for post in c.postconditions[:2]:
                    lines.append(f'      ensures: {post}')
                for pre in c.preconditions[:2]:
                    lines.append(f'      requires: {pre}')

        axioms = theory.all_axioms()
        if axioms:
            lines.append('  Axioms:')
            for name, a in sorted(axioms.items()):
                lines.append(f'    {name}: {a.statement}')
                if a.conditions:
                    lines.append(f'      when: {", ".join(a.conditions)}')

    return '\n'.join(lines)
